def solve(n, m, a, k):
    dp = [[0 for _ in range(m)] for _ in range(n)]
    for i in range(n):
        dp[i][a[i] - 1] += 1
        for j in range(m):
            dp[i][j] += dp[i - 1][j]
    for i in range(m):
        if dp[n - 1][i] < k[i]:
            return False
    return True

n, m = map(int, input().split())
a = list(map(int, input().split()))
k = list(map(int, input().split()))
if solve(n, m, a, k):
    print("YES")
else:
    print("NO")
